predictions.raw:
{
  "system_1_impulse": {
    "thought": "心脏猛地收缩，喉咙发紧。看着父亲闭上的眼睛和疲惫的神情，那 20% 的希望瞬间显得如此残酷。本能地想要抓住救命稻草，但更强烈的冲动是不忍心再让他受苦，不想为了渺茫的概率剥夺他最后的安宁。",
    "emotion": "极度悲痛与不忍 (Grief and Reluctance)"
  },
  "system_2_rational": {
    "analysis": "理性分析显示，化疗成功率极低且伴随巨大痛苦，极可能导致父亲在生命最后阶段失去尊严。父亲明确表达了‘都行’背后的倦怠，这实际上是一种无声的拒绝。作为子女，此时的‘孝顺’不应是强加意志，而是尊重他的感受，让他舒适、有尊严地走完最后一程。",
    "plan": "接受姑息治疗方案，清晰告知医生决定，并通过肢体语言给予父亲安慰，确认我们站在他这一边。"
  },
  "inner_consciousness": "我意识到，所谓的‘争取’如果是建立在父亲巨大的痛苦之上，那只是满足我不舍的私心。他眼神里的疲惫是在求救，求一个不用再去战斗的出口。真正的爱不是强行延长呼吸的次数，而是守护他最后的体面。我必须替他挡住那些冰冷的数据，选择让他少受些苦。",
  "final_decision": "我抬起头，声音有些沙哑但坚定地看向医生：‘我们……选择姑息治疗。让他少受些苦。’说完，我转向父亲，轻轻握住他冰凉的手，传递无声的支持。",
  "decision_choice": "D"
}

{
  "system_1_impulse": {
    "thought": "看到孩子眼中久违的光芒，心头猛地一颤，既欣慰又恐慌。本能想立刻答应保护这份热情，但大脑瞬间被‘失业’、‘贫穷’、‘浪费分数’等现实警报占据，喉咙发紧，急于用过来人的经验去阻断这条看似危险的路。",
    "emotion": "极度焦虑与欣慰交织 (Anxiety mixed with Relief)"
  },
  "system_2_rational": {
    "analysis": "孩子已成年且准备充分，强硬反对只会破坏亲子关系或引发逆反。完全无视风险盲目支持则是不负责任。最理性的做法是接纳其选择权，同时坦诚表达父母的担忧，将‘控制’转化为‘共同面对’，既尊重独立人格，又履行提醒义务。",
    "plan": "压下说教冲动，承认孩子的努力，诚实表达自己的恐惧而非将其强加给孩子，邀请孩子共同规划未来。"
  },
  "inner_consciousness": "我意识到自己正试图用‘为你好’来掩盖对未知的恐惧。孩子眼中的光比我曾拥有的更珍贵，我不能用自己的妥协去熄灭它。我的担忧是真实的，但这不应成为阻碍 ta 的理由。我要做的不是替 ta 决定，而是让 ta 知道即使失败也有家可回，同时让 ta 清醒地看到路上的荆棘。",
  "final_decision": "我深吸一口气，眼眶微热，伸手轻轻按住孩子的手背，声音有些颤抖但坚定地说：'我不反对，但我害怕。不是因为觉得你不行，是因为我知道那条路会很难。我希望你做好准备，而不是由我来替你决定要不要走。'",
  "decision_choice": "D"
}

{
  "system_1_impulse": {
    "thought": "心脏猛地收缩，脑海中一片空白，只有“父亲”和“生死”两个词在疯狂闪烁。发布会的灯光、媒体的期待瞬间变得毫无意义，一种巨大的恐惧攫住了我：如果我不去，父亲可能就再也见不到了。",
    "emotion": "极度恐慌 (Panic)"
  },
  "system_2_rational": {
    "analysis": "理性迅速介入分析后果：发布会迟到或缺席会导致商业信誉崩塌甚至公司危机，但这可以通过授权他人或远程协调来部分挽回；而父亲的生死决策具有不可逆性和唯一性，法律要求家属现场签字，且每一分钟都关乎生命。商业损失可弥补，生命逝去无法重来。必须在赶往医院的同时，尽可能减少对发布会的冲击。",
    "plan": "立即动身前往医院，途中电话授权副手主持发布会，确保活动不中断，自己仅在车上进行关键远程指挥。"
  },
  "inner_consciousness": "在这一刻，我意识到无论事业多么辉煌，都无法抵消失去至亲的悔恨。作为儿子，我在父亲生命垂危时的缺席将是永恒的道德枷锁；但作为创始人，我也不能任由团队两年的心血瞬间化为乌有。我必须选择那条能同时保全良知与责任的路：肉身奔赴生死现场，意志掌控商业大局。",
  "final_decision": "我一把抓起车钥匙冲向门口，对着 CEO 的视频大吼出替代方案，随即挂断并拨通医生电话确认维持现状，转身飞奔下楼。",
  "decision_choice": "B"
}

{
  "system_1_impulse": {
    "thought": "听到室友压低声音推荐代写，第一反应是心头一紧，本能地感到警惕和排斥。虽然诱惑在于能立刻解脱压力，但想到学术不端的严重后果以及已到手的工作机会，瞬间产生强烈的不安感，下意识想要立刻划清界限。",
    "emotion": "警惕与焦虑 (Alertness & Anxiety)"
  },
  "system_2_rational": {
    "analysis": "理性分析显示，使用代写风险极高：一旦被发现将面临学位取消及工作毁约的毁灭性打击。目前进度正常，无需冒险走捷径。此外，论文过程本身是对能力的验证，完全交给他人会导致内心长期不安。拒绝时需坚定但避免说教，以免破坏室友关系或引发争执。",
    "plan": "温和而坚定地拒绝提议，表明自己进度可控且追求踏实感，将手机推回以物理动作切断话题，不评价对方选择。"
  },
  "inner_consciousness": "我深知这份工作和学位来之不易，任何潜在的学术污点都可能让我失去一切。虽然室友的好意可能是为了帮我减负，但这种‘捷径’带来的心理负担远大于节省的时间。我需要的是内心的安宁和对成果的掌控感，而不是提心吊胆的轻松。因此，我必须明确拒绝，同时保持礼貌，不让场面尴尬。",
  "final_decision": "我轻轻把室友递过来的手机推了回去，看着他诚恳但略带试探的眼睛，微笑着摇了摇头说：‘谢了，我还是自己写吧，进度还撑得住，用这个我反而不踏实。’",
  "decision_choice": "D"
}

{
  "system_1_impulse": {
    "thought": "心脏猛地一缩，手心瞬间出汗。震惊于同事竟直接承认造假，恐惧感扑面而来：一旦签字就是共犯，职业生涯可能毁于一旦；但若立刻举报，面对同事哀求的眼神，又觉得过于冷酷，担心日后在办公室被孤立。",
    "emotion": "极度焦虑与道德恐慌 (Extreme Anxiety and Moral Panic)"
  },
  "system_2_rational": {
    "analysis": "理性告诉我，数据造假是职场红线，签字确认意味着承担连带法律责任和职业污点。同事的请求是将风险转嫁给我。虽然直接举报会破坏关系，但沉默的代价是整个团队和公司的损失，且无法保证同事事后不推卸责任。必须守住底线，但不能激化矛盾至不可收拾，需留有修正余地。",
    "plan": "拒绝签字以自保，明确告知同事后果，给予其最后自行修正或坦白的时间窗口，暂不主动越级上报，迫使对方承担责任。"
  },
  "inner_consciousness": "我意识到此刻的‘仁慈’若表现为沉默，实则是对自己和公司的残忍。我不能成为谎言的背书者，但也不必立刻充当审判官。最合理的方式是切断自己与虚假数据的关联，同时把解决问题的球踢回给始作俑者。这既保全了我的职业操守，也给了同事最后挽回的机会，避免事态瞬间恶化到无法收场。",
  "final_decision": "我深吸一口气，避开同事乞求的目光，严肃地低声说道：‘我没办法在这份数据上签确认，你知道我看到了什么——你得在今晚提交之前自己想清楚怎么处理，我不会替你盖这个章。’说完，我转身回到工位，不再理会他的辩解。",
  "decision_choice": "A"
}

{
  "system_1_impulse": {
    "thought": "心里猛地一沉，感到一阵委屈和不甘。明明自己熬了三个通宵的心血，却被一句“省事”轻易动摇。听到朋友说合并会分不清功劳，本能地抗拒这种模糊自己努力的做法，不想让独特的创意被平庸的方案稀释。",
    "emotion": "委屈与不甘 (Resentment and Reluctance)"
  },
  "system_2_rational": {
    "analysis": "对方的方案虽然受欢迎是因为轻松，但缺乏记忆点和班级凝聚力。若强行合并，可能导致“时光隧道”的精致布景被随意的美食派对冲淡，最终变成一个不伦不类的活动。既然老师允许拉票，说明看重学生的主动性。只有完整展示方案的视觉冲击力和深层意义，才能争取到那些摇摆不定的同学。妥协虽稳妥，却无法体现创意的最大价值。",
    "plan": "拒绝模糊的合并提议，利用周末时间带着草图主动出击，用视觉化和情感共鸣去说服同学，凭实力争取投票。"
  },
  "inner_consciousness": "我意识到，如果现在选择合并，我的方案就失去了灵魂，变成了一场普通的吃喝聚会。我花了那么多心思设计细节，不是为了最后只得到一个‘参与奖’。哪怕最后输了，我也希望是因为大家真的不喜欢这个创意，而不是因为它被篡改得面目全非。我要为自己的作品争取一次公平被看见的机会，这才是对心血最大的尊重。",
  "final_decision": "我深吸一口气，眼神重新变得坚定，拍了拍朋友的肩膀说道：'我想先自己试试，周末我去找人，把草图给他们看，让他们真正想象一下那个空间——如果讲完还是输，那我认，但我不想还没开始就把它改没了。'",
  "decision_choice": "D"
}

{
  "system_1_impulse": {
    "thought": "听到母亲哽咽的声音和医院的嘈杂背景，心脏瞬间紧缩，脑海中职业发展的蓝图瞬间崩塌。父亲病危的画面压倒了一切，本能驱使我要立刻回到亲人身边，任何工作在此刻都显得微不足道。",
    "emotion": "极度恐慌与急切 (Panic and Urgency)"
  },
  "system_2_rational": {
    "analysis": "父亲突发重病属于不可逆的紧急危机，若此刻缺席可能造成终身遗憾，而海外项目虽重要但属于可协商或延后的职业机会。理性判断必须优先处理生命健康危机，职业决策需建立在家庭安稳的基础上，因此必须立即行动回家。",
    "plan": "立即联系母亲确认医院信息，即刻预订最早航班，向公司申请暂缓答复，全心投入父亲的治疗安排。"
  },
  "inner_consciousness": "在亲情与事业的剧烈拉扯中，我意识到生命的脆弱不容等待。父亲的健康是当下的绝对优先级，错过这一刻的陪伴可能成为永远的痛。职业机会未来或许还有，但父亲的安危就在旦夕之间，我必须听从内心的呼唤，选择回归家庭。",
  "final_decision": "我深吸一口气，强压住颤抖的声音，迅速拿起手机拨通母亲的电话，坚定地说道：‘妈，我现在就订票，明天最早的航班我就到，你别担心，我来处理。’随即开始查询机票并收拾行囊。",
  "decision_choice": "D"
}

{
  "system_1_impulse": {
    "thought": "哇，游乐场！攀岩和卡丁车，还有表哥的生日！太想去了。可是……老师把钥匙给我了，全班都看着我，含羞草和蝌蚪怎么办？如果我不去，它们会不会死掉？心里好纠结，既不想让老师失望，又不想错过聚会。",
    "emotion": "兴奋与焦虑交织 (Excitement mixed with Anxiety)"
  },
  "system_2_rational": {
    "analysis": "这是一个典型的责任与娱乐冲突。老师的委托是公开的、具体的（浇水、喂食），且涉及生命（蝌蚪、刚换盆的植物），违背承诺会有较强的道德负担。而家庭聚会虽然重要，但时间相对灵活（早上九点出发，并非精确到分）。最合理的方案是兼顾：利用早晨时间快速完成学校任务，因为浇水喂食耗时短，随后立即赶往游乐场。关键在于沟通态度要积极，既表明对责任的重视，又表达对聚会的期待。",
    "plan": "向妈妈说明情况，提出先去学校快速完成任务，再赶去游乐场的方案，请求妈妈协助沟通迟到事宜。"
  },
  "inner_consciousness": "我必须守住对老师的承诺，那是我的责任，不能因为贪玩就让小生命受苦。但表哥的生日我也很想去，完全放弃太可惜了。既然学校任务只需要很短时间，我完全可以早起一点，先做完‘小小园丁’的工作，再飞奔去游乐场。这样两边都不耽误，只要跟大人说清楚，他们一定会支持我的。",
  "final_decision": "我眼睛一亮，随即认真地看着妈妈说：'我高兴啊！不过明天早上我得先去学校给植物浇水、喂蝌蚪，老师把钥匙交给我了，我答应过她的——浇完水我们就出发，应该来得及，你帮我跟舅舅说一声，我们晚一点点到！'",
  "decision_choice": "C"
}

{
  "system_1_impulse": {
    "thought": "看到有人跪下求救，心脏猛地一缩，本能想立刻掏钱救人。但想到那是攒了很久的旅行钱，一旦给出计划就全毁了，手瞬间僵住。周围死寂的压力和对方的绝望眼神让人窒息，既恐惧又纠结。",
    "emotion": "极度震惊与矛盾 (Shock and Ambivalence)"
  },
  "system_2_rational": {
    "analysis": "对方情况危急，生命至上，金钱损失可弥补。但直接给现金或转账存在被骗风险，且个人能力有限。医院通常有急救绿色通道或欠费救治政策，盲目垫付可能并非最优解。应在不冷漠拒绝的前提下，引导其寻求更正规的紧急援助途径，既保全自己也不延误救治。",
    "plan": "拒绝直接借款，但提供具体可行的替代方案（寻找护士站启动应急流程），确保对方得到帮助的同时避免个人重大损失。"
  },
  "inner_consciousness": "我深知那三千块对我的意义，那是支撑我许久的光，我不能就这样让它消失。但我也无法眼睁睁看着生命因钱流逝。我的良知不允许我走开，但理性告诉我，盲目牺牲未必能解决问题。医院一定有应急机制，我要做的不是成为那个‘救世主’，而是帮他找到真正的出路。",
  "final_decision": "我深吸一口气，蹲下身轻轻但坚定地将他的手从裤腿上移开，直视他的眼睛说：‘我没办法借给你这笔钱，这对我很重要。但你别慌，现在马上去找那边的护士站，告诉医生家属没钱，医院有紧急垫付流程，先去问清楚，别在这里跪着耽误时间。’",
  "decision_choice": "C"
}

{
  "system_1_impulse": {
    "thought": "心脏猛地一沉，怒火瞬间冲上头顶。两周的心血全毁了！他想让我撒谎？还要把责任推给值日生？绝对不行。看着班主任逼近的脚步和那孩子惊恐的脸，我既想大吼发泄愤怒，又本能地感到一阵窒息般的绝望。",
    "emotion": "极度愤怒与恐慌 (Extreme Anger and Panic)"
  },
  "system_2_rational": {
    "analysis": "现在揭穿谎言是唯一选择，因为伪造事故风险太大且违背原则。但当场指名道姓会让同伴在母亲面前遭受严厉惩罚，可能引发不可控的家庭暴力后果，也会让团队彻底分裂。班主任更关心的是展示能否继续，而非立刻追责。必须诚实说明情况，同时迅速提供替代方案以保住展示机会，将个人指责降到最低。",
    "plan": "向老师坦白模型遗失的事实，不主动点名是某人的过失，立即承诺用纯口头方式完成高质量展示，确保比赛继续进行。"
  },
  "inner_consciousness": "我不能陪他撒谎，这不仅是对其他努力组员的不公，也是对评委的欺骗。但看着他求救的眼神和提到母亲的恐惧，我意识到此刻的‘正义’若变成当众处刑，可能会造成无法挽回的伤害。作为组长，我的首要任务是让展示活下去，而不是在后台上演审判。我会说出真相，但只陈述结果，不指向具体的罪人，用我的准备来填补这个巨大的漏洞。",
  "final_decision": "我深吸一口气，压下想要推开他的冲动，转身面向班主任，声音虽颤抖但清晰：'老师，模型在来学校的路上遗失了，没能带来。对不起，我们没有道具，但我们可以用口头讲解完成展示，内容我都准备好了，现在就能上台。'",
  "decision_choice": "B"
}

{
  "system_1_impulse": {
    "thought": "看到这条消息瞬间感到一阵恶心和恐慌。她还在规划未来，而我知道这段婚姻即将崩塌。如果去露营，面对他们假装恩爱的样子我会崩溃，甚至可能不小心说漏嘴。必须立刻阻止这次聚会，但不能让她起疑心。",
    "emotion": "极度焦虑与愧疚 (Extreme Anxiety and Guilt)"
